function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm to find the minimum time to reach node n-1
    // Use a priority queue (min-heap) to process nodes by earliest arrival time
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map();
    dist.set(0, 0);

    while (pq.length > 0) {
        // Extract the node with the smallest arrival time
        pq.sort((a, b) => a[0] - b[0]);
        const [time, node] = pq.shift()!;

        // If we've reached the destination, return the time
        if (node === n - 1) {
            return time;
        }

        // Skip if we've already found a better path to this node
        if (dist.has(node) && dist.get(node)! < time) {
            continue;
        }

        // Explore all outgoing edges from the current node
        if (adj.has(node)) {
            for (const edge of adj.get(node)! ) {
                const { to, start, end } = edge;
                // Check if we can use this edge at the current time
                if (time >= start && time <= end) {
                    // We can take this edge, move to the next node at time + 1
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                } else {
                    // If the edge is not available at current time, we can wait until it becomes available
                    // The earliest we can use this edge is at start time
                    const earliestTime = Math.max(time, start);
                    const newTime = earliestTime + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                }
            }
        }
    }

    // If we've exhausted all possibilities and haven't reached the destination
    return -1;
}

